dotaz.relacni_algebra:
{mycustomers[agent_id, first_name, last_name, address] * agents(name = 'Juan Roberts')[agent_id]}
\
{mycustomers[agent_id, first_name, last_name, address] * agents(name != 'Juan Roberts')[agent_id]}

dotaz.sql:
-- Delete any existing payments for customers 6 and 7. DELETE FROM payment WHERE contract_id IN ( SELECT contract_id FROM contracts WHERE cus_id IN (6, 7) ); COMMIT;
-- Insert payments for all contracts of customer 6. INSERT INTO payment (contract_id, payment_date, payment_method, amount) SELECT contract_id, CURRENT_DATE AS payment_date, 'Credit Card' AS payment_method, 10000 + FLOOR(RANDOM() * 5000) AS amount -- Random amount between 10,000 and 15,000 FROM contracts WHERE cus_id = 6;
-- Insert payments for all contracts of customer 7. INSERT INTO payment (contract_id, payment_date, payment_method, amount) SELECT contract_id, CURRENT_DATE AS payment_date, 'Bank Transfer' AS payment_method, 10000 + FLOOR(RANDOM() * 5000) AS amount -- Random amount between 10,000 and 15,000 FROM contracts WHERE cus_id = 7;
